import { useEffect, useState } from 'react';
import { AdminService } from '../../../services/api';
import { Plus, Trash2, Image as ImageIcon, Search } from 'lucide-react';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';

export const AdminArtworks = () => {
  const [artworks, setArtworks] = useState<any[]>([]);
  const [search, setSearch] = useState('');

  const fetchData = async () => {
    try {
      const res: any = await AdminService.getAllArtworks();
      const actualData = res.data?.data || [];
      setArtworks(Array.isArray(actualData) ? actualData : []);
    } catch (err) { toast.error("Gallery Sync Failed"); }
  };

  useEffect(() => { fetchData(); }, []);

  const handleDelete = async (id: string) => {
    if (!window.confirm("Delete piece from archive?")) return;
    try {
      await AdminService.deleteArtwork(id);
      toast.success("Piece Removed");
      fetchData();
    } catch (err) { toast.error("Delete Failed"); }
  };

  const filtered = artworks.filter(art => 
    art.Title_In_English?.toLowerCase().includes(search.toLowerCase()) || 
    art.Artwork_ID?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-end">
        <h1 className="text-4xl font-black uppercase italic">Gallery <span className="text-primary">Artworks</span></h1>
        <Link to="/admin/artworks/add" className="bg-black text-white px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-primary transition-all shadow-xl">
          <Plus size={16} /> Catalog Piece
        </Link>
      </div>

      <div className="relative">
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
        <input 
          placeholder="Search Title or ID..." 
          className="w-full bg-white/5 border border-white/10 p-4 pl-12 rounded-2xl outline-none focus:border-primary text-white text-xs font-bold"
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {filtered.map((art: any) => (
          <div key={art._id} className="bg-[#0f0f0f] rounded-[2.5rem] overflow-hidden border border-white/5 group">
             <div className="h-56 bg-white/5 flex items-center justify-center overflow-hidden relative">
               <img 
                 src={art.Cloudinary_Image_URL || 'placeholder.jpg'} 
                 className="w-full h-full object-cover transition-transform group-hover:scale-105 duration-700" 
                 alt="" 
               />
               <div className="absolute top-4 left-4 bg-black/60 px-3 py-1 rounded-lg text-[9px] font-black text-primary">
                 {art.Artwork_ID}
               </div>
             </div>
             <div className="p-8">
               <h4 className="font-black uppercase text-xs italic truncate mb-1 text-white">{art.Title_In_English}</h4>
               <p className="text-[10px] font-bold text-gray-500 mb-6 uppercase">Artist: {art.Artist_Name || art.Artist_ID}</p>
               <div className="flex gap-2">
                 <Link to={`/admin/artworks/edit/${art.Artwork_ID}`} className="flex-1 py-3 bg-white/5 rounded-xl font-black text-[9px] uppercase text-center text-white hover:bg-primary hover:text-black transition-all">Modify</Link>
                 <button 
                   onClick={() => handleDelete(art.Artwork_ID)}
                   className="px-4 py-3 bg-red-500/10 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all"
                 >
                   <Trash2 size={14}/>
                 </button>
               </div>
             </div>
          </div>
        ))}
      </div>
    </div>
  );
};
